import React, { useState } from "react";
import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  BarElement,
  CategoryScale,
  LinearScale,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(BarElement, CategoryScale, LinearScale, Tooltip, Legend);

function ComparePage() {
  const [symbols, setSymbols] = useState("");
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);

  const fetchComparison = async () => {
    if (!symbols.trim()) {
      alert("Enter at least one symbol");
      return;
    }

    setLoading(true);
    try {
      const res = await fetch(
        `http://localhost:3000/api/compare?symbols=${symbols}`
      );
      const result = await res.json();
      setData(result.results || []);
    } catch (err) {
      console.error(err);
      alert("Error fetching stock comparison.");
    }
    setLoading(false);
  };

  // Prepare chart data if stocks fetched
  const labels = data.map((s) => s.symbol);
  const priceData = data.map((s) => s.price || 0);
  const marketCapData = data.map((s) =>
    s.marketCap ? s.marketCap / 1e9 : 0
  );
  const peData = data.map((s) => (s.pe ? s.pe : 0));

  const chartOptions = {
    responsive: true,
    plugins: {
      legend: {
        display: false,
      },
      tooltip: {
        callbacks: {
          label: (context) => {
            return context.dataset.label + ": " + context.formattedValue;
          },
        },
      },
    },
    scales: {
      y: {
        beginAtZero: true,
      },
    },
    animation: {
      duration: 1500,
      easing: "easeOutBounce",
    },
  };

  const sectionStyle = {
    background: "#f7f9fc",
    borderRadius: "8px",
    padding: "1rem",
    marginBottom: "2rem",
    boxShadow: "0 0 8px rgba(0,0,0,0.1)",
  };

  return (
    <div
      style={{
        maxWidth: "1200px",
        margin: "0 auto",
        padding: "2rem",
        fontFamily: "Arial, sans-serif",
      }}
    >
      <h2 style={{ textAlign: "center", marginBottom: "1.5rem" }}>
        Stock Comparison
      </h2>

      <div
        style={{
          display: "flex",
          marginBottom: "2rem",
          justifyContent: "center",
        }}
      >
        <input
          value={symbols}
          onChange={(e) => setSymbols(e.target.value)}
          placeholder="Enter comma-separated symbols (e.g. RELIANCE.NS, TCS.NS)"
          style={{
            padding: "0.8rem",
            width: "60%",
            borderRadius: "5px",
            border: "1px solid #ccc",
            fontSize: "1rem",
          }}
        />
        <button
          onClick={fetchComparison}
          style={{
            background: "#007bff",
            color: "white",
            border: "none",
            padding: "0.8rem 1.5rem",
            marginLeft: "1rem",
            cursor: "pointer",
            borderRadius: "5px",
            fontWeight: "bold",
            transition: "all 0.3s",
          }}
          onMouseEnter={(e) => {
            e.target.style.background = "#0056b3";
          }}
          onMouseLeave={(e) => {
            e.target.style.background = "#007bff";
          }}
          disabled={loading}
        >
          {loading ? "Loading..." : "Compare"}
        </button>
      </div>

      {data.length > 0 && (
        <>
          {/* Bar chart - Price */}
          <div style={sectionStyle}>
            <h3>Price Comparison</h3>
            <Bar
              data={{
                labels,
                datasets: [
                  {
                    label: "Price (₹ or $)",
                    data: priceData,
                    backgroundColor: "#36a2eb",
                  },
                ],
              }}
              options={chartOptions}
            />
          </div>

          {/* Bar chart - Market Cap */}
          <div style={sectionStyle}>
            <h3>Market Cap (in Billions)</h3>
            <Bar
              data={{
                labels,
                datasets: [
                  {
                    label: "Market Cap (B)",
                    data: marketCapData,
                    backgroundColor: "#4caf50",
                  },
                ],
              }}
              options={chartOptions}
            />
          </div>

          {/* Bar chart - PE Ratio */}
          <div style={sectionStyle}>
            <h3>PE Ratio Comparison</h3>
            <Bar
              data={{
                labels,
                datasets: [
                  {
                    label: "PE Ratio",
                    data: peData,
                    backgroundColor: "#ff9800",
                  },
                ],
              }}
              options={chartOptions}
            />
          </div>

          {/* Table of other details */}
          <div style={sectionStyle}>
            <h3>Stock Details</h3>
            <table
              style={{
                width: "100%",
                borderCollapse: "collapse",
              }}
            >
              <thead
                style={{
                  backgroundColor: "#007bff",
                  color: "white",
                }}
              >
                <tr>
                  <th style={{ padding: "10px", textAlign: "left" }}>
                    Symbol
                  </th>
                  <th style={{ padding: "10px", textAlign: "left" }}>Name</th>
                  <th style={{ padding: "10px", textAlign: "left" }}>
                    Dividend Yield
                  </th>
                  <th style={{ padding: "10px", textAlign: "left" }}>
                    52W High
                  </th>
                  <th style={{ padding: "10px", textAlign: "left" }}>
                    52W Low
                  </th>
                </tr>
              </thead>
              <tbody>
                {data.map((stock, index) => (
                  <tr
                    key={index}
                    style={{
                      backgroundColor:
                        index % 2 === 0 ? "#f2f2f2" : "transparent",
                    }}
                  >
                    <td style={{ padding: "10px" }}>{stock.symbol}</td>
                    <td style={{ padding: "10px" }}>{stock.name}</td>
                    <td style={{ padding: "10px" }}>
                      {stock.dividendYield !== null
                        ? `${(stock.dividendYield * 100).toFixed(2)}%`
                        : "N/A"}
                    </td>
                    <td style={{ padding: "10px" }}>
                      {stock.fiftyTwoWeekHigh}
                    </td>
                    <td style={{ padding: "10px" }}>
                      {stock.fiftyTwoWeekLow}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </>
      )}
    </div>
  );
}

export default ComparePage;
